using Microsoft.ML.Data;

namespace TicketClassifier.Models;

public class TicketData
{
    [LoadColumn(0)]
    public string Subject { get; set; } = string.Empty;

    [LoadColumn(1)]
    public string Description { get; set; } = string.Empty;

    [LoadColumn(2)]
    public float Priority { get; set; }

    [LoadColumn(3)]
    public string Category { get; set; } = string.Empty;
}

public class TicketPrediction
{
    [ColumnName("PredictedLabel")]
    public string Category { get; set; } = string.Empty;

    public float[] Score { get; set; } = [];
}

namespace TicketClassifier.Models;

public class TicketRequest
{
    public string Subject { get; set; } = string.Empty;
    public string Description { get; set; } = string.Empty;
    public int Priority { get; set; }
}

public class TicketClassificationResult
{
    public string PredictedCategory { get; set; } = string.Empty;
    public Dictionary<string, float> Confidence { get; set; } = new();
}

namespace TicketClassifier.Models;

public class ModelEvaluationMetrics
{
    public double MacroAccuracy { get; set; }
    public double MicroAccuracy { get; set; }
    public double LogLoss { get; set; }
    public double LogLossReduction { get; set; }
    public int TrainingSampleCount { get; set; }
    public string[] Categories { get; set; } = [];
    public PerClassMetric[] PerClassMetrics { get; set; } = [];
}

public class PerClassMetric
{
    public string Category { get; set; } = string.Empty;
    public double Precision { get; set; }
    public double Recall { get; set; }
}

using Microsoft.ML;
using TicketClassifier.Models;

namespace TicketClassifier.Services;

public class TicketClassifierService
{
    private readonly MLContext _mlContext;
    private readonly ITransformer _model;
    private readonly PredictionEngine<TicketData, TicketPrediction> _predictionEngine;
    private readonly ModelEvaluationMetrics _metrics;
    private readonly string[] _categories;

    public TicketClassifierService(string dataPath)
    {
        _mlContext = new MLContext(seed: 42);

        var dataView = _mlContext.Data.LoadFromTextFile<TicketData>(
            dataPath, hasHeader: true, separatorChar: ',', allowQuoting: true);

        // Extract distinct category labels for confidence mapping
        var categoryColumn = _mlContext.Data
            .CreateEnumerable<TicketData>(dataView, reuseRowObject: false)
            .Select(t => t.Category)
            .Distinct()
            .OrderBy(c => c)
            .ToArray();
        _categories = categoryColumn;

        // Build the training pipeline:
        // 1. Combine Subject + Description into a single text feature
        // 2. Featurize text via n-grams
        // 3. Include Priority as a numeric feature
        // 4. Concatenate all features
        // 5. Map Category string to a key for the trainer
        // 6. Train with SdcaMaximumEntropy (multiclass)
        // 7. Map predicted key back to string
        var pipeline = _mlContext.Transforms.Text.FeaturizeText(
                outputColumnName: "SubjectFeaturized", inputColumnName: nameof(TicketData.Subject))
            .Append(_mlContext.Transforms.Text.FeaturizeText(
                outputColumnName: "DescriptionFeaturized", inputColumnName: nameof(TicketData.Description)))
            .Append(_mlContext.Transforms.Concatenate("Features",
                "SubjectFeaturized", "DescriptionFeaturized", nameof(TicketData.Priority)))
            .Append(_mlContext.Transforms.Conversion.MapValueToKey("Label", nameof(TicketData.Category)))
            .Append(_mlContext.MulticlassClassification.Trainers.SdcaMaximumEntropy(
                labelColumnName: "Label", featureColumnName: "Features"))
            .Append(_mlContext.Transforms.Conversion.MapKeyToValue(
                "PredictedLabel", "PredictedLabel"));

        // With a small dataset, train on all data and evaluate on the same set
        // to report baseline metrics. A real system would use cross-validation.
        _model = pipeline.Fit(dataView);

        var predictions = _model.Transform(dataView);
        var eval = _mlContext.MulticlassClassification.Evaluate(predictions, labelColumnName: "Label");

        _metrics = new ModelEvaluationMetrics
        {
            MacroAccuracy = eval.MacroAccuracy,
            MicroAccuracy = eval.MicroAccuracy,
            LogLoss = eval.LogLoss,
            LogLossReduction = eval.LogLossReduction,
            TrainingSampleCount = (int)dataView.GetRowCount()!,
            Categories = _categories,
            PerClassMetrics = eval.PerClassLogLoss
                .Select((logLoss, i) => new PerClassMetric
                {
                    Category = i < _categories.Length ? _categories[i] : $"Class_{i}",
                    Precision = i < eval.ConfusionMatrix.PerClassPrecision.Count
                        ? eval.ConfusionMatrix.PerClassPrecision[i] : 0,
                    Recall = i < eval.ConfusionMatrix.PerClassRecall.Count
                        ? eval.ConfusionMatrix.PerClassRecall[i] : 0
                })
                .ToArray()
        };

        _predictionEngine = _mlContext.Model
            .CreatePredictionEngine<TicketData, TicketPrediction>(_model);
    }

    public TicketClassificationResult Predict(TicketRequest request)
    {
        var ticketData = new TicketData
        {
            Subject = request.Subject,
            Description = request.Description,
            Priority = request.Priority
        };

        var prediction = _predictionEngine.Predict(ticketData);

        var confidence = new Dictionary<string, float>();
        for (var i = 0; i < _categories.Length && i < prediction.Score.Length; i++)
        {
            confidence[_categories[i]] = prediction.Score[i];
        }

        return new TicketClassificationResult
        {
            PredictedCategory = prediction.Category,
            Confidence = confidence
        };
    }

    public ModelEvaluationMetrics GetMetrics() => _metrics;
}

using Microsoft.AspNetCore.Mvc;
using TicketClassifier.Models;
using TicketClassifier.Services;

namespace TicketClassifier.Controllers;

[ApiController]
[Route("api/[controller]")]
public class TicketsController : ControllerBase
{
    private readonly TicketClassifierService _classifier;

    public TicketsController(TicketClassifierService classifier)
    {
        _classifier = classifier;
    }

    /// <summary>
    /// Predict the category of a support ticket.
    /// </summary>
    [HttpPost("classify")]
    public ActionResult<TicketClassificationResult> Classify([FromBody] TicketRequest request)
    {
        if (string.IsNullOrWhiteSpace(request.Subject) && string.IsNullOrWhiteSpace(request.Description))
            return BadRequest("Subject or Description is required.");

        if (request.Priority is < 1 or > 3)
            return BadRequest("Priority must be between 1 and 3.");

        return Ok(_classifier.Predict(request));
    }

    /// <summary>
    /// Get model evaluation metrics from training.
    /// </summary>
    [HttpGet("metrics")]
    public ActionResult<ModelEvaluationMetrics> GetMetrics()
    {
        return Ok(_classifier.GetMetrics());
    }
}

